command:
const mod = game.modules.get('gmants-roleplayr-integration');
if (!mod?.active) {
  ui.notifications.error("GMAnt's Roleplayr Integration module is not active.");
  return;
}
const api = game.gmantsRoleplayr?.api;
if (!api?.isConfigured) {
  ui.notifications.warn("Roleplayr is not configured. Run 'Configure Roleplayr' first.");
  return;
}
try {
  const me = await api.getMe();
  const lines = [
    `<strong>Roleplayr Sync Status</strong>`,
    `Campaign: ${me.campaign_name ?? me.campaign_id ?? '(unbound)'}`,
    `World: ${me.world_name ?? me.world_id ?? '(unbound)'}`,
    `User: ${me.user_id ?? '(unknown)'}`,
  ];
  ChatMessage.create({
    content: `<div>${lines.join('<br/>')}</div>`,
    whisper: [game.user.id],
  });
} catch (err) {
  ui.notifications.error(`Roleplayr check failed: ${err.message}`);
  console.error('[gmants-roleplayr-integration]', err);
}
